import Database from 'better-sqlite3';
import path from 'path';

const dbPath = path.join(process.cwd(), 'inventario.db');
const db = new Database(dbPath);

db.pragma('foreign_keys = ON');

db.exec(`
  CREATE TABLE IF NOT EXISTS areas (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    nombre TEXT UNIQUE NOT NULL,
    coordinador TEXT
  );

  CREATE TABLE IF NOT EXISTS equipos (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    area_id INTEGER,
    numeroinventario TEXT,
    nombre_responsable_inventario TEXT,
    marca_modelo TEXT,
    almacenamiento TEXT,
    memoria_ram TEXT,
    procesador TEXT,
    monitor TEXT,
    mouse_teclado TEXT,
    observaciones TEXT,
    es_mal_estado INTEGER DEFAULT 0,
    fecha TEXT,
    FOREIGN KEY (area_id) REFERENCES areas (id) ON DELETE CASCADE
  );
`);

// Migración segura: añade la columna si ya existe la tabla sin ella
const cols = db.pragma('table_info(equipos)');
if (!cols.some(c => c.name === 'es_mal_estado')) {
  db.exec(`ALTER TABLE equipos ADD COLUMN es_mal_estado INTEGER DEFAULT 0;`);
}

export default db;